   589→    /**
   590→     * Add the leader to the ready nodes if the batch is ready
   591→     *
   592→     * @param exhausted 'true' is the buffer pool is exhausted
   593→     * @param part The partition
   594→     * @param leader The leader for the partition
   595→     * @param waitedTimeMs How long batch waited
   596→     * @param backingOff Is backing off
   597→     * @param backoffAttempts Number of attempts for calculating backoff delay
   598→     * @param full Is batch full
   599→     * @param nextReadyCheckDelayMs The delay for next check
   600→     * @param readyNodes The set of ready nodes (to be filled in)
   601→     * @return The delay for next check
   602→     */
   603→    private long batchReady(boolean exhausted, TopicPartition part, Node leader,
   604→                            long waitedTimeMs, boolean backingOff, int backoffAttempts,
   605→                            boolean full, long nextReadyCheckDelayMs, Set<Node> readyNodes) {
   606→        if (!readyNodes.contains(leader) && !isMuted(part)) {
   607→            long timeToWaitMs = backingOff ? retryBackoff.backoff(backoffAttempts > 0 ? backoffAttempts - 1 : 0) : lingerMs;
   608→            boolean expired = waitedTimeMs >= timeToWaitMs;
   609→            boolean transactionCompleting = transactionManager != null && transactionManager.isCompleting();
   610→            boolean sendable = full
   611→                    || expired
   612→                    || exhausted
   613→                    || closed
   614→                    || flushInProgress()
   615→                    || transactionCompleting;
   616→            if (sendable && !backingOff) {
   617→                readyNodes.add(leader);
   618→            } else {
   619→                long timeLeftMs = Math.max(timeToWaitMs - waitedTimeMs, 0);
   620→                // Note that this results in a conservative estimate since an un-sendable partition may have
   621→                // a leader that will later be found to have sendable data. However, this is good enough
   622→                // since we'll just wake up and then sleep again for the remaining time.
   623→                nextReadyCheckDelayMs = Math.min(timeLeftMs, nextReadyCheckDelayMs);
   624→            }
   625→        }
   626→        return nextReadyCheckDelayMs;
   627→    }
   628→
   629→    /**
   630→     * Iterate over partitions to see which one have batches ready and collect leaders of those
   631→     * partitions into the set of ready nodes.  If partition has no leader, add the topic to the set
   632→     * of topics with no leader.  This function also calculates stats for adaptive partitioning.
   633→     *
   634→     * @param metadataSnapshot      The cluster metadata
   635→     * @param nowMs                 The current time
   636→     * @param topic                 The topic
   637→     * @param topicInfo             The topic info
   638→     * @param nextReadyCheckDelayMs The delay for next check
   639→     * @param readyNodes            The set of ready nodes (to be filled in)
   640→     * @param unknownLeaderTopics   The set of topics with no leader (to be filled in)
   641→     * @return The delay for next check
   642→     */
   643→    private long partitionReady(MetadataSnapshot metadataSnapshot, long nowMs, String topic,
   644→                                TopicInfo topicInfo,
   645→                                long nextReadyCheckDelayMs, Set<Node> readyNodes, Set<String> unknownLeaderTopics) {
   646→        ConcurrentMap<Integer, Deque<ProducerBatch>> batches = topicInfo.batches;
   647→        // Collect the queue sizes for available partitions to be used in adaptive partitioning.
   648→        int[] queueSizes = null;
   649→        int[] partitionIds = null;
   650→        if (enableAdaptivePartitioning && batches.size() >= metadataSnapshot.cluster().partitionsForTopic(topic).size()) {
   651→            // We don't do adaptive partitioning until we scheduled at least a batch for all
   652→            // partitions (i.e. we have the corresponding entries in the batches map), we just
   653→            // do uniform.  The reason is that we build queue sizes from the batches map,
   654→            // and if an entry is missing in the batches map, then adaptive partitioning logic
   655→            // won't know about it and won't switch to it.
   656→            queueSizes = new int[batches.size()];
   657→            partitionIds = new int[queueSizes.length];
   658→        }
   659→
   660→        int queueSizesIndex = -1;
   661→        boolean exhausted = this.free.queued() > 0;
   662→        for (Map.Entry<Integer, Deque<ProducerBatch>> entry : batches.entrySet()) {
   663→            TopicPartition part = new TopicPartition(topic, entry.getKey());
   664→            // Advance queueSizesIndex so that we properly index available
   665→            // partitions.  Do it here so that it's done for all code paths.
   666→
   667→            Node leader = metadataSnapshot.cluster().leaderFor(part);
   668→            if (leader != null && queueSizes != null) {
   669→                ++queueSizesIndex;
   670→                assert queueSizesIndex < queueSizes.length;
   671→                partitionIds[queueSizesIndex] = part.partition();
   672→            }
   673→
   674→            Deque<ProducerBatch> deque = entry.getValue();
   675→
   676→            final long waitedTimeMs;
   677→            final boolean backingOff;
   678→            final int backoffAttempts;
   679→            final int dequeSize;
   680→            final boolean full;
   681→
   682→            OptionalInt leaderEpoch = metadataSnapshot.leaderEpochFor(part);
   683→
   684→            // This loop is especially hot with large partition counts. So -
   685→
   686→            // 1. We should avoid code that increases synchronization between application thread calling
   687→            // send(), and background thread running runOnce(), see https://issues.apache.org/jira/browse/KAFKA-16226
   688→
   689→            // 2. We are careful to only perform the minimum required inside the
   690→            // synchronized block, as this lock is also used to synchronize producer threads
   691→            // attempting to append() to a partition/batch.
   692→
   693→            synchronized (deque) {
   694→                // Deques are often empty in this path, esp with large partition counts,
   695→                // so we exit early if we can.
   696→                ProducerBatch batch = deque.peekFirst();
   697→                if (batch == null) {
   698→                    continue;
   699→                }
   700→
   701→                waitedTimeMs = batch.waitedTimeMs(nowMs);
   702→                batch.maybeUpdateLeaderEpoch(leaderEpoch);
   703→                backingOff = shouldBackoff(batch.hasLeaderChangedForTheOngoingRetry(), batch, waitedTimeMs);
   704→                backoffAttempts = batch.attempts();
   705→                dequeSize = deque.size();
   706→                full = dequeSize > 1 || batch.isFull();
   707→            }
   708→
   709→            if (leader == null) {
   710→                // This is a partition for which leader is not known, but messages are available to send.
   711→                // Note that entries are currently not removed from batches when deque is empty.
   712→                unknownLeaderTopics.add(part.topic());
   713→            } else {
   714→                if (queueSizes != null)
   715→                    queueSizes[queueSizesIndex] = dequeSize;
   716→                if (partitionAvailabilityTimeoutMs > 0) {
   717→                    // Check if we want to exclude the partition from the list of available partitions
   718→                    // if the broker hasn't responded for some time.
   719→                    NodeLatencyStats nodeLatencyStats = nodeStats.get(leader.id());
   720→                    if (nodeLatencyStats != null) {
   721→                        // NOTE: there is no synchronization between reading metrics,
   722→                        // so we read ready time first to avoid accidentally marking partition
   723→                        // unavailable if we read while the metrics are being updated.
   724→                        long readyTimeMs = nodeLatencyStats.readyTimeMs;
   725→                        if (readyTimeMs - nodeLatencyStats.drainTimeMs > partitionAvailabilityTimeoutMs)
   726→                            --queueSizesIndex;
   727→                    }
   728→                }
   729→
   730→                nextReadyCheckDelayMs = batchReady(exhausted, part, leader, waitedTimeMs, backingOff,
   731→                    backoffAttempts, full, nextReadyCheckDelayMs, readyNodes);
   732→            }
   733→        }
   734→
   735→        // We've collected the queue sizes for partitions of this topic, now we can calculate
   736→        // load stats.  NOTE: the stats are calculated in place, modifying the
   737→        // queueSizes array.
   738→        topicInfo.builtInPartitioner.updatePartitionLoadStats(queueSizes, partitionIds, queueSizesIndex + 1);
   739→        return nextReadyCheckDelayMs;
   740→    }
   741→
   742→    /**
   743→     * Get a list of nodes whose partitions are ready to be sent, and the earliest time at which any non-sendable
   744→     * partition will be ready; Also return the flag for whether there are any unknown leaders for the accumulated
   745→     * partition batches.
   746→     * <p>
   747→     * A destination node is ready to send data if:
   748→     * <ol>
   749→     * <li>There is at least one partition that is not backing off its send
   750→     * <li><b>and</b> those partitions are not muted (to prevent reordering if
   751→     *   {@value org.apache.kafka.clients.producer.ProducerConfig#MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION}
   752→     *   is set to one)</li>
   753→     * <li><b>and <i>any</i></b> of the following are true</li>
   754→     * <ul>
   755→     *     <li>The record set is full</li>
   756→     *     <li>The record set has sat in the accumulator for at least lingerMs milliseconds</li>
   757→     *     <li>The accumulator is out of memory and threads are blocking waiting for data (in this case all partitions
   758→     *     are immediately considered ready).</li>
   759→     *     <li>The accumulator has been closed</li>
   760→     * </ul>
   761→     * </ol>
   762→     */
   763→    public ReadyCheckResult ready(MetadataSnapshot metadataSnapshot, long nowMs) {
   764→        Set<Node> readyNodes = new HashSet<>();
   765→        long nextReadyCheckDelayMs = Long.MAX_VALUE;
   766→        Set<String> unknownLeaderTopics = new HashSet<>();
   767→        // Go topic by topic so that we can get queue sizes for partitions in a topic and calculate
   768→        // cumulative frequency table (used in partitioner).
   769→        for (Map.Entry<String, TopicInfo> topicInfoEntry : this.topicInfoMap.entrySet()) {
   770→            final String topic = topicInfoEntry.getKey();
   771→            nextReadyCheckDelayMs = partitionReady(metadataSnapshot, nowMs, topic, topicInfoEntry.getValue(), nextReadyCheckDelayMs, readyNodes, unknownLeaderTopics);
   772→        }
   773→        return new ReadyCheckResult(readyNodes, nextReadyCheckDelayMs, unknownLeaderTopics);
   774→    }
