   776→    /**
   777→     * Check whether there are any batches which haven't been drained
   778→     */
   779→    public boolean hasUndrained() {
   780→        for (TopicInfo topicInfo : topicInfoMap.values()) {
   781→            for (Deque<ProducerBatch> deque : topicInfo.batches.values()) {
   782→                synchronized (deque) {
   783→                    if (!deque.isEmpty())
   784→                        return true;
   785→                }
   786→            }
   787→        }
   788→        return false;
   789→    }
