   978→        // first to avoid accidentally marking a partition unavailable if the reader gets
   979→        // values between updates.
   980→        NodeLatencyStats nodeLatencyStats = nodeStats.computeIfAbsent(nodeId, id -> new NodeLatencyStats(nowMs));
