  1119→    /**
  1120→     * Abort all incomplete batches (whether they have been sent or not)
  1121→     */
  1122→    void abortBatches(final RuntimeException reason) {
  1123→        for (ProducerBatch batch : incomplete.copyAll()) {
  1124→            Deque<ProducerBatch> dq = getDeque(batch.topicPartition);
  1125→            synchronized (dq) {
  1126→                batch.abortRecordAppends();
  1127→                dq.remove(batch);
  1128→            }
  1129→            batch.abort(reason);
  1130→            deallocate(batch);
  1131→        }
  1132→    }
