   257→    /**
   258→     * Add a record to the accumulator, return the append result
   259→     * <p>
   260→     * The append result will contain the future metadata, and flag for whether the appended batch is full or a new batch is created
   261→     * <p>
   262→     *
   263→     * @param topic The topic to which this record is being sent
   264→     * @param partition The partition to which this record is being sent or RecordMetadata.UNKNOWN_PARTITION
   265→     *                  if any partition could be used
   266→     * @param timestamp The timestamp of the record
   267→     * @param key The key for the record
   268→     * @param value The value for the record
   269→     * @param headers the Headers for the record
   270→     * @param callbacks The callbacks to execute
   271→     * @param maxTimeToBlock The maximum time in milliseconds to block for buffer memory to be available
   272→     * @param nowMs The current time, in milliseconds
   273→     * @param cluster The cluster metadata
   274→     */
   275→    public RecordAppendResult append(String topic,
   276→                                     int partition,
   277→                                     long timestamp,
   278→                                     byte[] key,
   279→                                     byte[] value,
   280→                                     Header[] headers,
   281→                                     AppendCallbacks callbacks,
   282→                                     long maxTimeToBlock,
   283→                                     long nowMs,
   284→                                     Cluster cluster) throws InterruptedException {
   285→        TopicInfo topicInfo = topicInfoMap.computeIfAbsent(topic, k -> new TopicInfo(createBuiltInPartitioner(logContext, k, batchSize)));
   286→
   287→        // We keep track of the number of appending thread to make sure we do not miss batches in
   288→        // abortIncompleteBatches().
   289→        appendsInProgress.incrementAndGet();
   290→        ByteBuffer buffer = null;
   291→        if (headers == null) headers = Record.EMPTY_HEADERS;
   292→        try {
   293→            // Loop to retry in case we encounter partitioner's race conditions.
   294→            while (true) {
   295→                // If the message doesn't have any partition affinity, so we pick a partition based on the broker
   296→                // availability and performance.  Note, that here we peek current partition before we hold the
   297→                // deque lock, so we'll need to make sure that it's not changed while we were waiting for the
   298→                // deque lock.
   299→                final BuiltInPartitioner.StickyPartitionInfo partitionInfo;
   300→                final int effectivePartition;
   301→                if (partition == RecordMetadata.UNKNOWN_PARTITION) {
   302→                    partitionInfo = topicInfo.builtInPartitioner.peekCurrentPartitionInfo(cluster);
   303→                    effectivePartition = partitionInfo.partition();
   304→                } else {
   305→                    partitionInfo = null;
   306→                    effectivePartition = partition;
   307→                }
   308→
   309→                // Now that we know the effective partition, let the caller know.
   310→                setPartition(callbacks, effectivePartition);
   311→
   312→                // check if we have an in-progress batch
   313→                Deque<ProducerBatch> dq = topicInfo.batches.computeIfAbsent(effectivePartition, k -> new ArrayDeque<>());
   314→                synchronized (dq) {
   315→                    // After taking the lock, validate that the partition hasn't changed and retry.
   316→                    if (partitionChanged(topic, topicInfo, partitionInfo, dq, nowMs, cluster))
   317→                        continue;
   318→
   319→                    RecordAppendResult appendResult = tryAppend(timestamp, key, value, headers, callbacks, dq, nowMs);
   320→                    if (appendResult != null) {
   321→                        // If queue has incomplete batches we disable switch (see comments in updatePartitionInfo).
   322→                        boolean enableSwitch = allBatchesFull(dq);
   323→                        topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, appendResult.appendedBytes, cluster, enableSwitch);
   324→                        return appendResult;
   325→                    }
   326→                }
   327→
   328→                if (buffer == null) {
   329→                    int size = Math.max(this.batchSize, AbstractRecords.estimateSizeInBytesUpperBound(
   330→                            RecordBatch.CURRENT_MAGIC_VALUE, compression.type(), key, value, headers));
   331→                    log.trace("Allocating a new {} byte message buffer for topic {} partition {} with remaining timeout {}ms", size, topic, effectivePartition, maxTimeToBlock);
   332→                    // This call may block if we exhausted buffer space.
   333→                    buffer = free.allocate(size, maxTimeToBlock);
   334→                    // Update the current time in case the buffer allocation blocked above.
   335→                    // NOTE: getting time may be expensive, so calling it under a lock
   336→                    // should be avoided.
   337→                    nowMs = time.milliseconds();
   338→                }
   339→
   340→                synchronized (dq) {
   341→                    // After taking the lock, validate that the partition hasn't changed and retry.
   342→                    if (partitionChanged(topic, topicInfo, partitionInfo, dq, nowMs, cluster))
   343→                        continue;
   344→
   345→                    RecordAppendResult appendResult = appendNewBatch(topic, effectivePartition, dq, timestamp, key, value, headers, callbacks, buffer, nowMs);
   346→                    // Set buffer to null, so that deallocate doesn't return it back to free pool, since it's used in the batch.
   347→                    if (appendResult.newBatchCreated)
   348→                        buffer = null;
   349→                    // If queue has incomplete batches we disable switch (see comments in updatePartitionInfo).
   350→                    boolean enableSwitch = allBatchesFull(dq);
   351→                    topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, appendResult.appendedBytes, cluster, enableSwitch);
   352→                    return appendResult;
   353→                }
   354→            }
   355→        } finally {
   356→            free.deallocate(buffer);
   357→            appendsInProgress.decrementAndGet();
   358→        }
   359→    }
   360→
   361→    /**
   362→     * Append a new batch to the queue
   363→     *
   364→     * @param topic The topic
   365→     * @param partition The partition (cannot be RecordMetadata.UNKNOWN_PARTITION)
   366→     * @param dq The queue
   367→     * @param timestamp The timestamp of the record
   368→     * @param key The key for the record
   369→     * @param value The value for the record
   370→     * @param headers the Headers for the record
   371→     * @param callbacks The callbacks to execute
   372→     * @param buffer The buffer for the new batch
   373→     * @param nowMs The current time, in milliseconds
   374→     */
   375→    private RecordAppendResult appendNewBatch(String topic,
   376→                                              int partition,
   377→                                              Deque<ProducerBatch> dq,
   378→                                              long timestamp,
   379→                                              byte[] key,
   380→                                              byte[] value,
   381→                                              Header[] headers,
   382→                                              AppendCallbacks callbacks,
   383→                                              ByteBuffer buffer,
   384→                                              long nowMs) {
   385→        assert partition != RecordMetadata.UNKNOWN_PARTITION;
   386→
   387→        RecordAppendResult appendResult = tryAppend(timestamp, key, value, headers, callbacks, dq, nowMs);
   388→        if (appendResult != null) {
   389→            // Somebody else found us a batch, return the one we waited for! Hopefully this doesn't happen often...
   390→            return appendResult;
   391→        }
   392→
   393→        MemoryRecordsBuilder recordsBuilder = recordsBuilder(buffer);
   394→        ProducerBatch batch = new ProducerBatch(new TopicPartition(topic, partition), recordsBuilder, nowMs);
   395→        FutureRecordMetadata future = Objects.requireNonNull(batch.tryAppend(timestamp, key, value, headers,
   396→                callbacks, nowMs));
   397→
   398→        dq.addLast(batch);
   399→        incomplete.add(batch);
   400→
   401→        return new RecordAppendResult(future, dq.size() > 1 || batch.isFull(), true, batch.estimatedSizeInBytes());
   402→    }
   403→
   404→    private MemoryRecordsBuilder recordsBuilder(ByteBuffer buffer) {
   405→        return MemoryRecords.builder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, compression, TimestampType.CREATE_TIME, 0L);
   406→    }
   407→
   408→    /**
   409→     * Check if all batches in the queue are full.
   410→     */
   411→    private boolean allBatchesFull(Deque<ProducerBatch> deque) {
   412→        // Only the last batch may be incomplete, so we just check that.
   413→        ProducerBatch last = deque.peekLast();
   414→        return last == null || last.isFull();
   415→    }
   416→
   417→     /**
   418→     *  Try to append to a ProducerBatch.
   419→     *
   420→     *  If it is full, we return null and a new batch is created. We also close the batch for record appends to free up
   421→     *  resources like compression buffers. The batch will be fully closed (ie. the record batch headers will be written
   422→     *  and memory records built) in one of the following cases (whichever comes first): right before send,
   423→     *  if it is expired, or when the producer is closed.
   424→     */
   425→    private RecordAppendResult tryAppend(long timestamp, byte[] key, byte[] value, Header[] headers,
   426→                                         Callback callback, Deque<ProducerBatch> deque, long nowMs) {
   427→        if (closed)
   428→            throw new KafkaException("Producer closed while send in progress");
   429→        ProducerBatch last = deque.peekLast();
   430→        if (last != null) {
   431→            int initialBytes = last.estimatedSizeInBytes();
   432→            FutureRecordMetadata future = last.tryAppend(timestamp, key, value, headers, callback, nowMs);
   433→            if (future == null) {
   434→                last.closeForRecordAppends();
   435→            } else {
   436→                int appendedBytes = last.estimatedSizeInBytes() - initialBytes;
   437→                return new RecordAppendResult(future, deque.size() > 1 || last.isFull(), false, appendedBytes);
   438→            }
   439→        }
   440→        return null;
   441→    }
