   447→    public void resetNextBatchExpiryTime() {
   448→        nextBatchExpiryTimeMs = Long.MAX_VALUE;
   449→    }
   450→
   451→    public void maybeUpdateNextBatchExpiryTime(ProducerBatch batch) {
   452→        if (batch.createdMs + deliveryTimeoutMs  > 0) {
   453→            // the non-negative check is to guard us against potential overflow due to setting
   454→            // a large value for deliveryTimeoutMs
   455→            nextBatchExpiryTimeMs = Math.min(nextBatchExpiryTimeMs, batch.createdMs + deliveryTimeoutMs);
   456→        } else {
   457→            log.warn("Skipping next batch expiry time update due to addition overflow: "
   458→                + "batch.createMs={}, deliveryTimeoutMs={}", batch.createdMs, deliveryTimeoutMs);
   459→        }
   460→    }
