   742→    /**
   743→     * Get a list of nodes whose partitions are ready to be sent, and the earliest time at which any non-sendable
   744→     * partition will be ready; Also return the flag for whether there are any unknown leaders for the accumulated
   745→     * partition batches.
   746→     * <p>
   747→     * A destination node is ready to send data if:
   748→     * <ol>
   749→     * <li>There is at least one partition that is not backing off its send
   750→     * <li><b>and</b> those partitions are not muted (to prevent reordering if
   751→     *   {@value org.apache.kafka.clients.producer.ProducerConfig#MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION}
   752→     *   is set to one)</li>
   753→     * <li><b>and <i>any</i></b> of the following are true</li>
   754→     * <ul>
   755→     *     <li>The record set is full</li>
   756→     *     <li>The record set has sat in the accumulator for at least lingerMs milliseconds</li>
   757→     *     <li>The accumulator is out of memory and threads are blocking waiting for data (in this case all partitions
   758→     *     are immediately considered ready).</li>
   759→     *     <li>The accumulator has been closed</li>
   760→     * </ul>
   761→     * </ol>
   762→     */
   763→    public ReadyCheckResult ready(MetadataSnapshot metadataSnapshot, long nowMs) {
   764→        Set<Node> readyNodes = new HashSet<>();
   765→        long nextReadyCheckDelayMs = Long.MAX_VALUE;
   766→        Set<String> unknownLeaderTopics = new HashSet<>();
   767→        // Go topic by topic so that we can get queue sizes for partitions in a topic and calculate
   768→        // cumulative frequency table (used in partitioner).
   769→        for (Map.Entry<String, TopicInfo> topicInfoEntry : this.topicInfoMap.entrySet()) {
   770→            final String topic = topicInfoEntry.getKey();
   771→            nextReadyCheckDelayMs = partitionReady(metadataSnapshot, nowMs, topic, topicInfoEntry.getValue(), nextReadyCheckDelayMs, readyNodes, unknownLeaderTopics);
   772→        }
   773→        return new ReadyCheckResult(readyNodes, nextReadyCheckDelayMs, unknownLeaderTopics);
   774→    }
