   791→    private boolean shouldBackoff(boolean hasLeaderChanged, final ProducerBatch batch, final long waitedTimeMs) {
   792→        boolean shouldWaitMore = batch.attempts() > 0 && waitedTimeMs < retryBackoff.backoff(batch.attempts() - 1);
   793→        boolean shouldBackoff = !hasLeaderChanged && shouldWaitMore;
   794→        if (log.isTraceEnabled()) {
   795→            if (shouldBackoff) {
   796→                log.trace(
   797→                    "For {}, will backoff", batch);
   798→            } else {
   799→                log.trace(
   800→                    "For {}, will not backoff, shouldWaitMore {}, hasLeaderChanged {}", batch,
   801→                    shouldWaitMore, hasLeaderChanged);
   802→            }
   803→        } else if (log.isDebugEnabled() && hasLeaderChanged) {
   804→            // Add less-verbose log at DEBUG.
   805→            log.debug("For {}, leader has changed, hence skipping backoff.", batch);
   806→        }
   807→        return shouldBackoff;
   808→    }
