   810→    private boolean shouldStopDrainBatchesForPartition(ProducerBatch first, TopicPartition tp) {
   811→        ProducerIdAndEpoch producerIdAndEpoch;
   812→        if (transactionManager != null) {
   813→            if (!transactionManager.isSendToPartitionAllowed(tp))
   814→                return true;
   815→
   816→            producerIdAndEpoch = transactionManager.producerIdAndEpoch();
   817→            if (!producerIdAndEpoch.isValid())
   818→                // we cannot send the batch until we have refreshed the producer id
   819→                return true;
   820→
   821→            if (!first.hasSequence()) {
   822→                if (transactionManager.hasInflightBatches(tp) && transactionManager.hasStaleProducerIdAndEpoch(tp)) {
   823→                    // Don't drain any new batches while the partition has in-flight batches with a different epoch
   824→                    // and/or producer ID. Otherwise, a batch with a new epoch and sequence number
   825→                    // 0 could be written before earlier batches complete, which would cause out of sequence errors
   826→                    return true;
   827→                }
   828→
   829→                if (transactionManager.hasUnresolvedSequence(first.topicPartition))
   830→                    // Don't drain any new batches while the state of previous sequence numbers
   831→                    // is unknown. The previous batches would be unknown if they were aborted
   832→                    // on the client after being sent to the broker at least once.
   833→                    return true;
   834→            }
   835→
   836→            int firstInFlightSequence = transactionManager.firstInFlightSequence(first.topicPartition);
   837→            // If the queued batch already has an assigned sequence, then it is being retried.
   838→            // In this case, we wait until the next immediate batch is ready and drain that.
   839→            // We only move on when the next in line batch is complete (either successfully or due to
   840→            // a fatal broker error). This effectively reduces our in flight request count to 1.
   841→            return firstInFlightSequence != RecordBatch.NO_SEQUENCE && first.hasSequence()
   842→                    && first.baseSequence() != firstInFlightSequence;
   843→        }
   844→        return false;
   845→    }
