  1171→    /**
  1172→     * Partitioner config for built-in partitioner
  1173→     */
  1174→    public static final class PartitionerConfig {
  1175→        private final boolean enableAdaptivePartitioning;
  1176→        private final long partitionAvailabilityTimeoutMs;
  1177→
  1178→        /**
  1179→         * Partitioner config
  1180→         *
  1181→         * @param enableAdaptivePartitioning If it's true, partition switching adapts to broker load, otherwise partition
  1182→         *        switching is random.
  1183→         * @param partitionAvailabilityTimeoutMs If a broker cannot process produce requests from a partition
  1184→         *        for the specified time, the partition is treated by the partitioner as not available.
